// src/pages/Internship.jsx
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import InternshipCard from '../components/InternshipCard';
import InternshipModal from '../components/InternshipModal';

export default function Internship() {
  const user = JSON.parse(localStorage.getItem('user'));
  const userRole = user?.role;
  const token = user?.token;

  const [internships, setInternships] = useState([]);
  const [applications, setApplications] = useState([]);
  const [search, setSearch] = useState('');
  const [modalOpen, setModalOpen] = useState(false);
  const [editingInternship, setEditingInternship] = useState(null);

  const fetchInternships = async () => {
    try {
      const res = await axios.get(`/api/internships?search=${search}`);
      setInternships(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const fetchApplications = async () => {
    if (userRole === 'Student') {
      const res = await axios.get('/api/internships/my-applications', {
        headers: { Authorization: `Bearer ${token}` },
      });
      const appliedIds = res.data.map((a) => a.internship._id);
      setApplications(appliedIds);
    }
  };

  useEffect(() => {
    fetchInternships();
    fetchApplications();
  }, [search]);

  const handleApply = async (id) => {
    try {
      await axios.post(`/api/internships/${id}/apply`, {}, {
        headers: { Authorization: `Bearer ${token}` },
      });
      fetchApplications();
    } catch (err) {
      console.error('Apply failed:', err.response?.data?.message);
    }
  };

  const handleSave = async (data) => {
    try {
      if (editingInternship) {
        await axios.put(`/api/internships/${editingInternship._id}`, data, {
          headers: { Authorization: `Bearer ${token}` },
        });
      } else {
        await axios.post('/api/internships', data, {
          headers: { Authorization: `Bearer ${token}` },
        });
      }
      fetchInternships();
      setEditingInternship(null);
    } catch (err) {
      console.error(err);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this internship?')) return;
    try {
      await axios.delete(`/api/internships/${id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      fetchInternships();
    } catch (err) {
      console.error(err);
    }
  };

  return (
    <div className="p-6">
      <div className="flex justify-between items-center mb-4">
        <input
          className="border px-3 py-1 rounded w-full max-w-md"
          placeholder="Search internships..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />

        {(userRole === 'Admin' || userRole === 'HR') && (
          <button
            className="bg-green-600 text-white px-4 py-2 rounded ml-4"
            onClick={() => {
              setEditingInternship(null);
              setModalOpen(true);
            }}
          >
            Add Internship
          </button>
        )}
      </div>

      <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
        {internships.map((internship) => (
          <InternshipCard
            key={internship._id}
            internship={internship}
            userRole={userRole}
            applied={applications.includes(internship._id)}
            onApply={handleApply}
            onEdit={(data) => {
              setEditingInternship(data);
              setModalOpen(true);
            }}
            onDelete={handleDelete}
          />
        ))}
      </div>

      <InternshipModal
        isOpen={modalOpen}
        onClose={() => {
          setModalOpen(false);
          setEditingInternship(null);
        }}
        onSave={handleSave}
        editingInternship={editingInternship}
      />
    </div>
  );
}
